class Solution:
    def maxPathSum(self, root: Optional[TreeNode]) -> int:
        self.ans = float('-inf')
        def gain(node):
            if not node: return 0
            l = max(0, gain(node.left))
            r = max(0, gain(node.right))
            self.ans = max(self.ans, node.val + l + r)
            return node.val + max(l, r)
        gain(root)
        return self.ans

